package main

import "fmt"

func main() {
    count := 0

    // This loop has no condition, so it runs forever!
    for {
        fmt.Println("Running...", count)
        count++

        // Wait... how do we stop it?
        if count == 5 {
            break 
        }
    }
    fmt.Println("Phew! We escaped.")
}
